<?php namespace App\Repositories\Attendance;use App\Repositories\BaseRepository;use App\Models\Attendance\LeaveRequest;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class LeaveRequestRepository extends BaseRepository{    public function __construct(LeaveRequest $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByEmployee(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function findByLeaveType(int $leaveTypeId): Collection    {        return $this->findByField('leave_type_id', $leaveTypeId);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->where(function ($q) use ($startDate, $endDate) {                $q->whereBetween('start_date', [$startDate, $endDate])->orWhereBetween('end_date', [$startDate, $endDate]);            })->get();    }    public function getPendingRequests(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function getApprovedRequests(): Collection    {        return $this->query()->where('status', 'approved')->get();    }    public function approve(int $id, ?string $approvedBy = null): bool    {        $data = ['status' => 'approved', 'approved_at' => now()];        if ($approvedBy) {            $data['approved_by'] = $approvedBy;        }        return $this->update($id, $data);    }    public function reject(int $id, string $reason): bool    {        return $this->update($id, ['status' => 'rejected', 'rejection_reason' => $reason]);    }    public function getCurrentLeaveBalance(int $employeeId, int $leaveTypeId): ?LeaveRequest    {        return $this->query()->where('employee_id', $employeeId)->where('leave_type_id', $leaveTypeId)->where('status', 'approved')->first();    }}